import cadquery as cq

class WebEdgeSelector(cq.Selector):
    def filter(self, objectList):
        res = []
        for o in objectList:
            if isinstance(o, cq.Edge):
                try:
                    if o.geomType() == "CIRCLE":
                        circ = o._geomAdaptor().Circle()
                        r = circ.Radius()
                        z = circ.Location().Z()
                        if (abs(r - 14.0) < 0.01 or abs(r - 44.0) < 0.01) and (abs(z - 3.0) < 0.01 or abs(z + 3.0) < 0.01):
                            res.append(o)
                except:
                    pass
        return res

